    Project.countDocuments({ 'phases.proposal.status': 'submitted' }),
    Project.countDocuments({ 'phases.ppt.status': 'submitted' }),
    Project.countDocuments({ 'phases.report.status': 'submitted' }),
    Project.countDocuments({ 'phases.prototype.status': 'submitted' }),
  ]);

  const totalPending = pendingProposals + pendingPPTs + pendingReports + pendingPrototypes;

  // Department breakdown
  const byDepartment = await Project.aggregate([
    { $match: { isActive: true } },
    { $group: { _id: '$department', count: { $sum: 1 } } },
    { $sort: { count: -1 } },
  ]);

  // Monthly submission trend (last 6 months)
  const sixMonthsAgo = new Date();
  sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);

  const monthlyTrend = await Project.aggregate([
    { $match: { createdAt: { $gte: sixMonthsAgo }, isActive: true } },
    {
      $group: {
        _id: { year: { $year: '$createdAt' }, month: { $month: '$createdAt' } },
        count: { $sum: 1 },
      },
    },
    { $sort: { '_id.year': 1, '_id.month': 1 } },
    {
      $project: {
        month: {
          $dateToString: {
            format: '%b %Y',
            date: { $dateFromParts: { year: '$_id.year', month: '$_id.month', day: 1 } },
          },
        },
        count: 1,
        _id: 0,
      },
    },
  ]);

  const completionRate = totalProjects > 0 ? Math.round((completedProjects / totalProjects) * 100) : 0;

  return {
    totalStudents,
    totalTeams,
    totalProjects,
    completedProjects,
    inProgressProjects,
    totalPending,
    pendingByPhase: { proposals: pendingProposals, ppts: pendingPPTs, reports: pendingReports, prototypes: pendingPrototypes },
    byDepartment: byDepartment.map((d) => ({ department: d._id || 'Unknown', count: d.count })),
    monthlyTrend,
    completionRate,
  };
};

export const getStudentAnalytics = async (userId) => {
  const user = await User.findById(userId);
  const team = await Team.findOne({ 'members.user': userId, isActive: true });
  const project = team ? await Project.findOne({ team: team._id, isActive: true }) : null;

  return {
    hasTeam: !!team,
    hasProject: !!project,
    teamName: team?.name,
    projectTitle: project?.title,
    currentPhase: project?.currentPhase || 'proposal',
    progress: project?.progress || 0,
    phaseStatuses: project?.phases || {},
    status: project?.status || 'not_started',
  };
};
