    formData.append('ppt', file);
    return api.post('/projects/ppt', formData, { headers: { 'Content-Type': 'multipart/form-data' }, timeout: 120000 });
  },

  submitReport: (file) => {
    const formData = new FormData();
    formData.append('report', file);
    return api.post('/projects/report', formData, { headers: { 'Content-Type': 'multipart/form-data' }, timeout: 120000 });
  },

  submitPrototype: (data, screenshots, zipFile) => {
    const formData = new FormData();
    formData.append('githubRepo', data.githubRepo);
    if (data.liveUrl) formData.append('liveUrl', data.liveUrl);
    if (data.demoVideoUrl) formData.append('demoVideoUrl', data.demoVideoUrl);
    if (screenshots) screenshots.forEach((file) => formData.append('screenshots', file));
    if (zipFile) formData.append('projectZip', zipFile);
    return api.post('/projects/prototype', formData, { headers: { 'Content-Type': 'multipart/form-data' }, timeout: 120000 });
  },

  reviewSubmission: (projectId, phase, data) =>
    api.patch(`/projects/${projectId}/review/${phase}`, data),
};
