import PPTPhase from './phases/PPTPhase.jsx';
import ReportPhase from './phases/ReportPhase.jsx';
import PrototypePhase from './phases/PrototypePhase.jsx';

const phaseMap = {
  proposal: ProposalPhase,
  ppt: PPTPhase,
  report: ReportPhase,
  prototype: PrototypePhase,
};

const Project = () => {
  const { user } = useAuth();
  const [project, setProject] = useState(null);
  const [team, setTeam] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const [activePhase, setActivePhase] = useState('proposal');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const [teamRes, projectRes] = await Promise.all([
        teamService.getMyTeam(),
        projectService.getMyProject(),
      ]);
      setTeam(teamRes.data.data);
      const proj = projectRes.data.data;
      setProject(proj);
      if (proj) setActivePhase(proj.currentPhase === 'completed' ? 'prototype' : proj.currentPhase);
    } catch {
      setProject(null);
    } finally {
      setIsLoading(false);
    }
  };

  const isLeader = team?.members?.some((m) => m.user._id === user?._id && m.role === 'leader');

  if (isLoading) return (
    <div className="max-w-5xl mx-auto space-y-6">
      <LoadingSkeleton count={3} height={20} />
    </div>
  );

  if (!team) return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-6">
        <h2 className="text-dark-50 font-black text-2xl">My Project</h2>
      </div>
      <div className="card">
        <EmptyState
          icon={Users}
          title="Join a team first"
          description="You need to be in a team before you can start a project."
          action={<Link to="/student/team" className="btn-primary">Go to Team</Link>}
        />
      </div>
    </div>
  );

  const ActivePhaseComponent = phaseMap[activePhase];

  const phaseOrder = ['proposal', 'ppt', 'report', 'prototype'];
  const activePhaseIndex = phaseOrder.indexOf(activePhase);
  const prevPhaseApproved =
    activePhaseIndex === 0 || project?.phases?.[phaseOrder[activePhaseIndex - 1]]?.status === 'approved';

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      {/* Header */}
      <div>
        <h2 className="text-dark-50 font-black text-2xl">Project</h2>
        <p className="text-dark-500 text-sm mt-1">Track your project through all phases</p>
      </div>

      {/* Project Overview Card */}
      <div className="card p-6">
        <div className="flex items-start justify-between gap-4 mb-6">
          <div>
            <p className="text-dark-500 text-xs font-semibold uppercase tracking-wider">Project Title</p>
            <h3 className="text-dark-50 text-xl font-black mt-1">
              {project?.title || (project ? 'Unnamed Project' : 'Not started')}
            </h3>
            <div className="flex flex-wrap gap-2 mt-2">
              <Badge variant="primary">{team.name}</Badge>
              {team.department && <Badge variant="info">{team.department}</Badge>}
              {project && (
                <Badge variant={project.status === 'completed' ? 'success' : 'warning'}>
                  {project.status?.replace('_', ' ') || 'In Progress'}
                </Badge>
              )}
            </div>
          </div>
          {project && (
            <div className="text-right flex-shrink-0">
              <p className="text-dark-500 text-xs font-semibold uppercase tracking-wider">Overall Progress</p>
              <p className="text-4xl font-black text-gradient">{project.progress}%</p>
            </div>
          )}
        </div>

        {project && (
          <ProgressBar value={project.progress} label="Project completion" />
        )}
      </div>

      {/* Phase Stepper */}
      {project && (
        <div className="card p-6">
          <h3 className="text-dark-100 font-bold text-sm uppercase tracking-wider mb-6">Project Phases</h3>
          <PhaseStepper
            phases={project.phases}
            currentPhase={activePhase}
            onPhaseClick={(phase) => setActivePhase(phase)}
          />
        </div>
      )}

      {/* Phase Content */}
      <div className="card p-6">
        {!project && !prevPhaseApproved && activePhase !== 'proposal' ? (
          <div className="flex flex-col items-center justify-center py-12 text-center">
            <div className="w-16 h-16 rounded-2xl bg-dark-800 border border-dark-700 flex items-center justify-center mb-4">
              <AlertCircle className="w-8 h-8 text-dark-600" />
            </div>
            <p className="text-dark-300 font-bold">Phase Locked</p>
            <p className="text-dark-600 text-sm mt-1">Complete the previous phase first.</p>
          </div>
        ) : (
          <>
            {/* Phase header */}
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-dark-100 font-bold text-lg capitalize">
                Phase {phaseOrder.indexOf(activePhase) + 1}: {activePhase === 'ppt' ? 'PPT Submission' : activePhase.charAt(0).toUpperCase() + activePhase.slice(1)}
              </h3>
              {project?.phases?.[activePhase]?.status && (
                <Badge
                  variant={
                    project.phases[activePhase].status === 'approved' ? 'success' :
                    project.phases[activePhase].status === 'rejected' ? 'error' :
                    project.phases[activePhase].status === 'submitted' ? 'warning' : 'info'
                  }
                >
                  {project.phases[activePhase].status.replace('_', ' ')}
                </Badge>
              )}
            </div>
            {ActivePhaseComponent && (
              <ActivePhaseComponent
                project={project}
                team={team}
                isLeader={isLeader}
                onUpdate={fetchData}
              />
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default Project;
