import Input from '../../../components/ui/Input.jsx';

const schema = z.object({
  title: z.string().min(5, 'Project title is required (min 5 chars)'),
  problemStatement: z.string().min(30, 'Problem statement must be at least 30 characters'),
  solution: z.string().min(30, 'Solution must be at least 30 characters'),
  expectedOutcome: z.string().min(20, 'Expected outcome is required'),
  domain: z.string().min(2, 'Domain is required'),
  innovation: z.string().optional(),
  futureScope: z.string().optional(),
  estimatedTimeline: z.string().optional(),
});

const DOMAINS = [
  'Web Development', 'Mobile App', 'Machine Learning / AI',
  'IoT', 'Cloud Computing', 'Cybersecurity', 'Data Science',
  'Blockchain', 'Robotics', 'Other',
];

const ProposalPhase = ({ project, team, isLeader, onUpdate }) => {
  const proposal = project?.proposalId;
  const phaseStatus = project?.phases?.proposal?.status || 'not_started';
  const [objectives, setObjectives] = useState(proposal?.objectives || ['']);
  const [techStack, setTechStack] = useState(proposal?.technologyStack || ['']);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const isEditable = isLeader && (phaseStatus === 'not_started' || phaseStatus === 'rejected');

