    resolver: zodResolver(schema),
    defaultValues: {
      title: proposal?.title || '',
      problemStatement: proposal?.problemStatement || '',
      solution: proposal?.solution || '',
      expectedOutcome: proposal?.expectedOutcome || '',
      domain: proposal?.domain || '',
      innovation: proposal?.innovation || '',
      futureScope: proposal?.futureScope || '',
      estimatedTimeline: proposal?.estimatedTimeline || '',
    },
  });

  const onSubmit = async (data) => {
    if (objectives.filter(Boolean).length === 0) {
      toast.error('Add at least one objective');
      return;
    }
    setIsSubmitting(true);
    try {
      await projectService.submitProposal({
        ...data,
        objectives: objectives.filter(Boolean),
        technologyStack: techStack.filter(Boolean),
      });
      toast.success('Proposal submitted! Waiting for instructor review.');
      onUpdate();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to submit proposal');
    } finally {
      setIsSubmitting(false);
    }
  };

  // View only mode (submitted, under_review, approved)
  if (phaseStatus === 'submitted' || phaseStatus === 'under_review' || phaseStatus === 'approved') {
    return (
      <div className="space-y-5">
        {proposal?.instructorComments && phaseStatus === 'rejected' && (
          <div className="p-4 rounded-xl bg-red-500/10 border border-red-500/20">
            <div className="flex items-center gap-2 mb-2">
              <MessageSquare className="w-4 h-4 text-red-400" />
              <p className="text-red-400 text-sm font-bold">Instructor Feedback</p>
            </div>
            <p className="text-dark-300 text-sm">{proposal.instructorComments}</p>
          </div>
        )}
        <ViewProposal proposal={proposal} phaseStatus={phaseStatus} />
      </div>
    );
  }

  if (!isEditable) {
    if (proposal) return <ViewProposal proposal={proposal} phaseStatus={phaseStatus} />;
    return (
      <div className="text-center py-12">
        <p className="text-dark-500">Only the team leader can submit the proposal.</p>
      </div>
    );
