```js
import jwt from 'jsonwebtoken';
import { User } from '../models/User.model.js';
import { ApiError } from '../utils/ApiError.js';

const generateTokens = async (userId) => {
  const user = await User.findById(userId);
  const accessToken = user.generateAccessToken();
  const refreshToken = user.generateRefreshToken();
  user.refreshToken = refreshToken;
  user.lastLogin = new Date();
  await user.save({ validateBeforeSave: false });
  return { accessToken, refreshToken };
};

const registerStudent = async (data) => {
  const { firstName, lastName, email, password, rollNumber, department, academicYear, phoneNumber } = data;
  const existingUser = await User.findOne({ email });
  if (existingUser) throw new ApiError(409, 'Email already registered');

  const user = await User.create({
    firstName,
    lastName,
    email,
    password,
    rollNumber,
    department,
    academicYear,
    phoneNumber,
    role: 'student',
  });

  return await User.findById(user._id).select('-password -refreshToken');
};

const loginUser = async (email, password) => {
  const user = await User.findOne({ email });
  if (!user) throw new ApiError(404, 'User not found');
  if (!user.isActive) throw new ApiError(403, 'Account is deactivated');

  const isPasswordValid = await user.isPasswordCorrect(password);
  if (!isPasswordValid) throw new ApiError(401, 'Invalid credentials');

  return user;
};

const refreshAccessToken = async (incomingRefreshToken) => {
  if (!incomingRefreshToken) throw new ApiError(401, 'Unauthorized request');

  const decodedToken = jwt.verify(incomingRefreshToken, process.env.REFRESH_TOKEN_SECRET);
  const user = await User.findById(decodedToken?._id);
  if (!user) throw new ApiError(401, 'Invalid refresh token');
  if (incomingRefreshToken !== user.refreshToken) throw new ApiError(401, 'Refresh token is expired or used');

  return user;
};

export const authService = { generateTokens, registerStudent, loginUser, refreshAccessToken };
```

### Step 2: Create src/controllers/auth.controller.js
```js
import { asyncHandler } from '../utils/asyncHandler.js';
import { ApiError } from '../utils/ApiError.js';
import { ApiResponse } from '../utils/ApiResponse.js';
import { authService } from '../services/auth.service.js';
import { User } from '../models/User.model.js';

const COOKIE_OPTIONS = {
  httpOnly: true,
  secure: process.env.NODE_ENV === 'production',
  sameSite: process.env.NODE_ENV === 'production' ? 'none' : 'lax',
};

const register = asyncHandler(async (req, res) => {
  const user = await authService.registerStudent(req.body);
  res.status(201).json(new ApiResponse(201, user, 'Student registered successfully'));
});

const login = asyncHandler(async (req, res) => {
  const { email, password } = req.body;
  if (!email || !password) throw new ApiError(400, 'Email and password are required');

  const user = await authService.loginUser(email, password);
  const { accessToken, refreshToken } = await authService.generateTokens(user._id);
  const loggedInUser = await User.findById(user._id).select('-password -refreshToken');

  res
    .status(200)
    .cookie('accessToken', accessToken, COOKIE_OPTIONS)
    .cookie('refreshToken', refreshToken, { ...COOKIE_OPTIONS, maxAge: 10 * 24 * 60 * 60 * 1000 })
    .json(new ApiResponse(200, { user: loggedInUser, accessToken }, 'Login successful'));
});

const logout = asyncHandler(async (req, res) => {
  await User.findByIdAndUpdate(req.user._id, { $unset: { refreshToken: 1 } }, { new: true });
  res
    .status(200)
    .clearCookie('accessToken', COOKIE_OPTIONS)
    .clearCookie('refreshToken', COOKIE_OPTIONS)
    .json(new ApiResponse(200, {}, 'Logout successful'));
});

const refreshToken = asyncHandler(async (req, res) => {
  const incomingRefreshToken = req.cookies.refreshToken || req.body.refreshToken;
  const user = await authService.refreshAccessToken(incomingRefreshToken);
  const { accessToken, refreshToken: newRefreshToken } = await authService.generateTokens(user._id);

  res
    .status(200)
    .cookie('accessToken', accessToken, COOKIE_OPTIONS)
    .cookie('refreshToken', newRefreshToken, { ...COOKIE_OPTIONS, maxAge: 10 * 24 * 60 * 60 * 1000 })
    .json(new ApiResponse(200, { accessToken }, 'Access token refreshed'));
});

const getMe = asyncHandler(async (req, res) => {
  res.status(200).json(new ApiResponse(200, req.user, 'User fetched successfully'));
});

export const authController = { register, login, logout, refreshToken, getMe };
```

