      ? await User.countDocuments({ role: 'student', isActive: true })
      : undefined,
    profileComplete: Boolean(
      req.user.firstName &&
      req.user.email &&
      (req.user.role === 'student' ? req.user.rollNumber : req.user.employeeId)
    ),
    role: req.user.role,
  };
  res.status(200).json(new ApiResponse(200, stats, 'Dashboard stats fetched'));
});

